/**
 * Return a new object with boolean properties indicating whether specific keys ('USER_VARIABLE', 'GROUP_ID', 'EMAIL') are present in 'types'.
 * by Telmo Chiri
 */
// Assign the value of this.TO_SEND_TYPE_CC to a local variable 'types'
// This is expected to be an array or a string containing the types to send.
let types = this.TO_SEND_TYPE_CC;

// The Array.prototype.includes() method (or String.prototype.includes()) is used
// to check for inclusion.
return {
    'USER_VARIABLE': types.includes('USER_VARIABLE'), // true if 'USER_VARIABLE' exists in types
    'GROUP_ID': types.includes('GROUP_ID'),           // true if 'GROUP_ID' exists in types
    'EMAIL': types.includes('EMAIL')                  // true if 'EMAIL' exists in types
};
